const headers = $input.first().json.headers || {};
const body = $input.first().json.body || $input.first().json;
const providedKey = (headers['x-api-key'] || headers['X-Api-Key'] || '').trim();
const expectedKey = 'gda-bridge-k9x2mq7r4n8v';
const requestId = 'req-' + Date.now() + '-' + Math.random().toString(36).slice(2,8);
if (providedKey !== expectedKey) {
  return [{ json: { __auth_failed: true, requestId, error: 'Unauthorized: invalid or missing x-api-key header' } }];
}
const required = ['owner','repo','baseBranch','newBranch','commitMessage','prTitle','files'];
const missing = required.filter(k => !body[k]);
if (missing.length > 0) {
  return [{ json: { __auth_failed: true, requestId, error: 'Missing required fields: ' + missing.join(', ') } }];
}
if (!Array.isArray(body.files) || body.files.length === 0) {
  return [{ json: { __auth_failed: true, requestId, error: 'files must be a non-empty array' } }];
}
for (const f of body.files) {
  if (!f.path || f.content === undefined) {
    return [{ json: { __auth_failed: true, requestId, error: 'Each file must have path and content' } }];
  }
}
return [{ json: { __auth_failed: false, requestId, owner: body.owner, repo: body.repo, baseBranch: body.baseBranch, newBranch: body.newBranch, commitMessage: body.commitMessage, prTitle: body.prTitle, prBody: body.prBody || '', files: body.files, receivedAt: new Date().toISOString() } }];

const ctx = $input.first().json;
const BASE = 'https://api.github.com';
const HEADERS = {
  'Accept': 'application/vnd.github+json',
  'X-GitHub-Api-Version': '2022-11-28',
  'Content-Type': 'application/json'
};

async function ghGet(path) {
  const r = await this.helpers.httpRequestWithAuthentication('httpHeaderAuth', { method: 'GET', url: BASE + path, headers: HEADERS });
  return r;
}
async function ghPost(path, body) {
  const r = await this.helpers.httpRequestWithAuthentication('httpHeaderAuth', { method: 'POST', url: BASE + path, headers: HEADERS, body: JSON.stringify(body) });
  return r;
}
async function ghPut(path, body) {
  const r = await this.helpers.httpRequestWithAuthentication('httpHeaderAuth', { method: 'PUT', url: BASE + path, headers: HEADERS, body: JSON.stringify(body) });
  return r;
}

// 1. Get base branch SHA
let refData;
try {
  refData = await ghGet.call(this, `/repos/${ctx.owner}/${ctx.repo}/git/ref/heads/${ctx.baseBranch}`);
} catch(e) {
  return [{ json: { __error: true, step: 'get_sha', message: `Could not find base branch '${ctx.baseBranch}'. Check repo and branch name. Detail: ${e.message}` } }];
}
const baseSha = refData?.object?.sha;
if (!baseSha) {
  return [{ json: { __error: true, step: 'get_sha', message: `Base branch '${ctx.baseBranch}' exists but SHA could not be read.` } }];
}

// 2. Create new branch
try {
  await ghPost.call(this, `/repos/${ctx.owner}/${ctx.repo}/git/refs`, {
    ref: `refs/heads/${ctx.newBranch}`,
    sha: baseSha
  });
} catch(e) {
  const msg = e.message || '';
  if (msg.includes('already exists') || msg.includes('422')) {
    // Branch already exists — continue, we'll write to it
  } else {
    return [{ json: { __error: true, step: 'create_branch', message: `Branch creation failed: ${msg}` } }];
  }
}

// 3. Commit each file
const commitUrls = [];
for (const file of ctx.files) {
  const encoding = file.encoding || 'utf-8';
  let b64;
  if (encoding === 'base64') {
    b64 = file.content;
  } else {
    b64 = Buffer.from(file.content, 'utf-8').toString('base64');
  }

  // Check if file exists on the new branch (to get SHA for update)
  let existingSha = null;
  try {
    const existing = await ghGet.call(this, `/repos/${ctx.owner}/${ctx.repo}/contents/${file.path}?ref=${ctx.newBranch}`);
    existingSha = existing?.sha || null;
  } catch(e) { /* file doesn't exist yet, that's fine */ }

  const putBody = { message: ctx.commitMessage, content: b64, branch: ctx.newBranch };
  if (existingSha) putBody.sha = existingSha;

  let commitResult;
  try {
    commitResult = await ghPut.call(this, `/repos/${ctx.owner}/${ctx.repo}/contents/${file.path}`, putBody);
  } catch(e) {
    return [{ json: { __error: true, step: 'commit_file', message: `Failed to commit ${file.path}: ${e.message}` } }];
  }
  if (commitResult?.commit?.html_url) commitUrls.push(commitResult.commit.html_url);
}

// 4. Open PR
let prResult;
try {
  prResult = await ghPost.call(this, `/repos/${ctx.owner}/${ctx.repo}/pulls`, {
    title: ctx.prTitle,
    body: ctx.prBody,
    head: ctx.newBranch,
    base: ctx.baseBranch
  });
} catch(e) {
  return [{ json: { __error: true, step: 'open_pr', message: `Files committed to branch '${ctx.newBranch}' but PR failed: ${e.message}`, branch: ctx.newBranch, commitUrls } }];
}

if (!prResult?.html_url) {
  return [{ json: { __error: true, step: 'open_pr', message: `PR response missing html_url. Branch '${ctx.newBranch}' was created and files committed.`, branch: ctx.newBranch, commitUrls } }];
}

return [{ json: {
  __error: false,
  owner: ctx.owner,
  repo: ctx.repo,
  branch: ctx.newBranch,
  baseBranch: ctx.baseBranch,
  commitUrls,
  pullRequestUrl: prResult.html_url,
  pullRequestNumber: prResult.number,
  requestId: ctx.requestId,
  receivedAt: ctx.receivedAt,
  completedAt: new Date().toISOString()
}}];

